content.css:
p {
  font-size: 20px;
  font-weight: bold;
}
p em {
  background: yellow;
  padding: 5px;
}
svg {
  pointer-events: none;
}
.glyph {
  cursor: pointer;
  pointer-events: visiblePainted;
}
.MicrosoftMap,
svg {
  cursor: default;
}
.pin path {
  stroke: #999;
  fill: #F2C811;
}
.pin.dirty path {
  fill: #f08300;
}
.pin.invalid path {
  fill: #c0c6c9;
}
.pin path:hover {
  stroke: black;
}
svg .flow {
  cursor: pointer;
}
.tip {
  pointer-events: none;
  position: absolute;
  display: flex;
}
.tip .arrow {
  width: 0px;
  height: 0px;
  border-style: solid;
  border-width: 7px;
  border-color: transparent;
}
.tip .content-wrap {
  padding: 7px;
  font-size: 11px;
}
.tip.top {
  flex-direction: column-reverse;
}
.tip.bottom {
  flex-direction: column;
}
.tip.left {
  flex-direction: row-reverse;
}
.tip.right {
  flex-direction: row;
}
.war {
  pointer-events: none;
  font-size: 11px;
}
.war .header {
  font-weight: bold;
  padding-bottom: 4px;
  font-size: 12px;
  color: darkred;
}
.war .row {
  display: table-row;
}
.war .sect {
  display: table-cell;
  text-transform: uppercase;
  padding-right: 10px;
  max-width: 200px;
}
.war .value {
  display: table-cell;
  max-width: 260px;
}
.info {
  pointer-events: none;
  font-size: 11px;
}
.info .header {
  font-weight: bold;
  padding-left: 1px;
  padding-bottom: 4px;
  max-width: 240px;
  letter-spacing: 1px;
  word-wrap: break-word;
}
.info .row {
  display: table-row;
}
.info .cell {
  display: table-cell;
  max-width: 240px;
  vertical-align: middle;
  padding-top: 1px;
  padding-bottom: 1px;
}
.info .color {
  max-width: 13px;
  padding: 1px 4px 1px 0px;
}
.info .color svg {
  height: 14px;
}
.info .title {
  font-family: helvetica, arial, sans-serif;
  text-transform: uppercase;
  padding-top: 3px;
  padding-right: 12px;
}
.info .value {
  font-family: helvetica, arial, sans-serif;
  font-weight: bold;
  white-space: nowrap;
  text-overflow: ellipsis;
  overflow: hidden;
}


/*# sourceMappingURL=visual.css.map*/
